import json
import sys

def mask_dataset(data):
    records = data["records"]
    rules = data["masking_rules"]

    def apply_mask(value, rule):
        v = str(value)
        if rule == "first_initial":
            return v[0] + "*" * 7
        elif rule == "partial_domain":
            local, domain = v.split("@")
            return local[0] + "***@" + domain
        elif rule == "last_four":
            return "***" + v[-4:]
        elif rule == "bookend":
            return v[:2] + "*" * 4 + v[-2:]
        return v

    masked_records = []
    masking_counts = {}
    fields_masked = 0

    for record in records:
        masked = {}
        for field, value in record.items():
            if field in rules:
                rule = rules[field]
                masked[field] = apply_mask(value, rule)
                masking_counts[rule] = masking_counts.get(rule, 0) + 1
                fields_masked += 1
            else:
                masked[field] = value
        masked_records.append(masked)

    result = {
        "masked_records": masked_records,
        "audit": {
            "records_processed": len(records),
            "fields_masked": fields_masked,
            "masking_applied": masking_counts
        }
    }

    print(json.dumps(result, indent=2, ensure_ascii=False))

data = json.loads(sys.stdin.read())
mask_dataset(data)
